     3→import { useState, useEffect, useCallback, useRef } from "react";
     4→import { socket } from "@/lib/socket";
     5→import {
     6→  getUser,
     7→  updateProfile,
     8→  uploadSelfie,
     9→  startScrape,
    10→  submitOnboarding,
    11→  UserProfile,
    12→} from "@/lib/api";
    13→import type { OnboardingData } from "@/lib/types";
    14→import GoogleSignIn from "@/components/phone/GoogleSignIn";
    15→import SelfieCapture from "@/components/phone/SelfieCapture";
    16→import QueueStatus from "@/components/phone/QueueStatus";
    17→
    18→type PhoneState = "loading" | "signin" | "questionnaire" | "queue" | "idle" | "recap";
    19→
    20→const STORAGE_KEY = "mirrorless_user_id";
    21→
    22→export default function PhonePage() {
    23→  const [state, setState] = useState<PhoneState>("loading");
    24→  const [user, setUser] = useState<UserProfile | null>(null);
    25→  const [error, setError] = useState("");
    26→  const [recapData, setRecapData] = useState<{
    27→    summary?: string;
    28→    items_shown?: number;
    29→    items_liked?: number;
    30→  }>({});
    31→
    32→  // Check for returning user on mount
    33→  useEffect(() => {
    34→    async function checkReturning() {
    35→      const savedId = localStorage.getItem(STORAGE_KEY);
    36→      if (savedId) {
    37→        try {
    38→          const existingUser = await getUser(savedId);
    39→          setUser(existingUser);
    40→          setState("queue");
    41→          return;
    42→        } catch {
    43→          localStorage.removeItem(STORAGE_KEY);
    44→        }
    45→      }
    46→      setState("signin");
    47→    }
    48→    checkReturning();
    49→  }, []);
    50→
    51→  // Connect socket when we have a user
    52→  useEffect(() => {
    53→    if (!user) return;
    54→    socket.connect();
    55→    socket.emit("join_room", { user_id: user.id });
    56→
    57→    const handleSessionEnded = (data: {
    58→      summary?: string;
    59→      items_shown?: number;
    60→      items_liked?: number;
    61→    }) => {
    62→      setRecapData(data || {});
    63→      setState("recap");
    64→    };
    65→
    66→    socket.on("session_ended", handleSessionEnded);
    67→
    68→    return () => {
    69→      socket.off("session_ended", handleSessionEnded);
    70→    };
    71→  }, [user]);
    72→
    73→  const handleSignInComplete = useCallback(
    74→    (profile: UserProfile, selfieBase64: string | null, displayName: string) => {
    75→      setUser(profile);
    76→      localStorage.setItem(STORAGE_KEY, profile.id);
    77→
    78→      // Fire-and-forget: update name, upload selfie, start scrape
    79→      updateProfile(profile.id, displayName).catch(() => {});
    80→      if (selfieBase64) {
    81→        uploadSelfie(profile.id, selfieBase64).catch(() => {});
    82→      }
    83→      startScrape(profile.id).catch(() => {});
    84→
    85→      setState("questionnaire");
    86→    },
    87→    []
    88→  );
    89→
    90→  const handleQuestionnaireSubmit = useCallback(
    91→    async (data: OnboardingData) => {
    92→      if (!user) return;
    93→      await submitOnboarding(user.id, data);
    94→      setState("queue");
    95→    },
    96→    [user]
    97→  );
    98→
    99→  const handleBecameActive = useCallback(() => {
   100→    setState("idle");
   101→  }, []);
   102→
   103→  const handleDone = useCallback(() => {
   104→    localStorage.removeItem(STORAGE_KEY);
   105→    setUser(null);
   106→    setRecapData({});
   107→    setState("signin");
   108→  }, []);
   109→
