  items_liked: number;
}

export interface BoothStats {
  total_users_today: number;
  avg_session_seconds: number;
  total_items_shown: number;
  total_items_liked: number;
}

export function getAdminQueue() {
  return request<AdminQueueEntry[]>("/admin/queue");
}

